DB_NAME = 'performance_app.db'


def init_db():
    conn = sqlite3.connect(DB_NAME)
    cursor = conn.cursor()
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT NOT NULL UNIQUE,
            email TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    ''')
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS orders (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER,
            product TEXT NOT NULL,
            amount DECIMAL(10, 2),
            status TEXT DEFAULT 'pending',
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (user_id) REFERENCES users (id)
        )
    ''')
    conn.commit()
    conn.close()


@capture_span('database.operation')
def execute_query(query, params=None, fetch=True):
    conn = sqlite3.connect(DB_NAME)
    conn.row_factory = sqlite3.Row
    cursor = conn.cursor()
    
    elasticapm.label(query_type=query.split()[0].upper())
    elasticapm.label(sql_query=query)
    
    if params:
        cursor.execute(query, params)
        elasticapm.label(query_params=str(params))
    else:
        cursor.execute(query)
    
    if fetch:
        result = cursor.fetchall()
        conn.close()
        return [dict(row) for row in result]
    else:
        conn.commit()
        last_id = cursor.lastrowid
        conn.close()
        return last_id


@capture_span('business.logic')
def process_user_data(username, email):
    time.sleep(0.1)
    
    elasticapm.label(username=username)
    elasticapm.label(email=email)
    
    if not username or not email:
        raise ValueError("Username and email are required")
    
    return {
        'processed': True,
        'username': username.lower(),
        'email': email.lower()
    }


@capture_span('business.calculation')
def calculate_order_total(items):
    total = 0
    for item in items:
        time.sleep(0.05)
        total += item.get('price', 0) * item.get('quantity', 1)
    
    elasticapm.label(items_count=len(items))
    elasticapm.label(total_amount=total)
    
    return total


@app.before_request
def before_request():
    set_custom_context({
        'request_id': request.headers.get('X-Request-ID', 'N/A'),
        'user_agent': request.headers.get('User-Agent', 'N/A'),
        'request_size': request.content_length or 0
    })


@app.after_request
def after_request(response):
    set_custom_context({
        'response_status': response.status_code,
        'response_size': response.content_length or 0
    })
    return response


