@app.route('/analytics', methods=['POST'])
def analytics():
    try:
        data = request.get_json()
        
        set_custom_context({
            'endpoint': 'analytics',
            'request_data': data
        })
        
        with capture_span('analytics.fetch_users', span_type='db.query'):
            users = execute_query('SELECT COUNT(*) as count FROM users')
            user_count = users[0]['count']
        
        with capture_span('analytics.fetch_orders', span_type='db.query'):
            orders = execute_query('SELECT COUNT(*) as count FROM orders')
            order_count = orders[0]['count']
        
        with capture_span('analytics.calculate_revenue', span_type='db.query'):
            revenue = execute_query('SELECT SUM(amount) as total FROM orders WHERE status = ?', ('completed',))
            total_revenue = revenue[0]['total'] or 0
        
        with capture_span('analytics.processing', span_type='custom'):
            time.sleep(0.2)
            analytics_data = {
                'total_users': user_count,
                'total_orders': order_count,
                'total_revenue': total_revenue,
                'average_order_value': total_revenue / order_count if order_count > 0 else 0
            }
        
        set_custom_context({'analytics_result': analytics_data})
        
        return jsonify({
            'success': True,
            'analytics': analytics_data
        })
        
    except Exception as e:
        elasticapm.capture_exception()
        return jsonify({'error': str(e)}), 500


